// =============================================
// VALIDAR ANTI-SPAM + EXTRAIR BODY
// =============================================
const body = $input.item.json.body;

const website   = String(body.website  || '').trim(); // honeypot
const email     = String(body.email    || '').trim();
const nome      = String(body.nome     || '').trim();
const whatsapp  = String(body.whatsapp || '').trim();

const honeypotOk = website === '';
const hasEmail   = email !== '' && /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(email);
const hasNome    = nome !== '';
const hasPhone   = whatsapp !== '';

console.log('=== ANTI-SPAM VIP POUSADA ===');
console.log('Honeypot vazio?', honeypotOk);
console.log('E-mail válido?', hasEmail);
console.log('Tem nome?', hasNome);
console.log('Tem WhatsApp?', hasPhone);

if (!honeypotOk || !hasEmail || !hasNome || !hasPhone) {
  throw new Error('Validação falhou — possível spam ou campos obrigatórios ausentes');
}

return body;

// =============================================
// PREPARAR E NORMALIZAR DADOS
// =============================================
const data = $input.item.json;

return {
  nome:                String(data.nome         || '').trim(),
  email:               String(data.email        || '').trim().toLowerCase(),
  whatsapp:            String(data.whatsapp     || '').trim(),
  pousada_nome:        data.pousada_nome ? String(data.pousada_nome).trim() : '',
  quartos:             data.quartos     ? String(data.quartos).trim()     : '',
  cidade:              data.cidade      ? String(data.cidade).trim()      : '',
  status:              'novo',
  diagnostico_enviado: false,
  url_origem:          data.url_origem  || '',
  criado_em:           new Date().toISOString()
};

